function solve(n: number, edges: number[][], label: string): number {
    const adj = new Array(n).fill(0).map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let maxLen = 1;

    for (let start = 0; start < n; start++) {
        const stack: { node: number, bitmask: number, path: string }[] = [];
        stack.push({ node: start, bitmask: 1 << start, path: label[start] });

        while (stack.length > 0) {
            const { node, bitmask, path } = stack.pop();
            if (isPalindrome(path)) {
                maxLen = Math.max(maxLen, path.length);
            }
            for (const neighbor of adj[node]) {
                if (!(bitmask & (1 << neighbor))) {
                    const newBitmask = bitmask | (1 << neighbor);
                    const newPath = path + label[neighbor];
                    stack.push({ node: neighbor, bitmask: newBitmask, path: newPath });
                }
            }
        }
    }

    return maxLen;
}

function isPalindrome(s: string): boolean {
    return s === s.split('').reverse().join('');
}

