fn solve(n: i64, edges: Vec<Vec<i64>>, label: String) -> i64 {
    let n = n as usize;
    let mut adj = vec![vec![]; n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj[u].push(v);
        adj[v].push(u);
    }

    let mut max_len = 1;

    for start in 0..n {
        let mut stack = vec![];
        stack.push((start, 1 << start, label.chars().nth(start).unwrap().to_string()));
        while let Some((node, bitmask, path)) = stack.pop() {
            if is_palindrome(&path) {
                max_len = max_len.max(path.len() as i64);
            }
            for &neighbor in &adj[node] {
                if (bitmask & (1 << neighbor)) == 0 {
                    let new_bitmask = bitmask | (1 << neighbor);
                    let new_path = format!("{}{}", path, label.chars().nth(neighbor).unwrap());
                    stack.push((neighbor, new_bitmask, new_path));
                }
            }
        }
    }

    max_len
}

fn is_palindrome(s: &str) -> bool {
    s == s.chars().rev().collect::<String>()
}
