        let v = edge[1] as usize;
        adj[u].push(v);
        adj[v].push(u);
    }

    let label_chars: Vec<char> = label.chars().collect();
    let mut max_len = 1;

    for start in 0..n {
        let mut stack = vec![];
        stack.push((start, 1 << start, label_chars[start].to_string()));
